var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아줌마, 아직 안 지쳤나 보네?","JPN":"おばさん、まだ疲れていないみたいね。","ENG":"Old lady, are you still up?","TWN":"大嬸體力還不錯嘛！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 나도 질 수 없지! 최강의 필살 스파이크를 날려 주겠어!","JPN":"ならば私も負けてられない！　最強の必殺スパイクを飛ばしてやる！","ENG":"Okay, I can do better! I’ll show you the ultimate spike!","TWN":"那我當然也不能輸！看我的宇宙最強殺球！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"간다! 스승님의 이름에 부끄럽지 않은 위력의 강 스파이크!","JPN":"いくよ！　師匠の名に恥じない威力の強スパイク！","ENG":"Here we go! A super powerful spike that won’t embarrass the name of my Master!","TWN":"去吧！不負師父之名的超強威力球！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"언제까지 애처럼 기술 이름에 목매달 작정이야!","JPN":"いつまで子どもみたいに、技名にこだわるつもり？","ENG":"Stop making up stupid skill names!","TWN":"你是三歲小孩嗎？打個球花招那麼多！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"다른 전대가 널 보고 뭐라고 생각했겠어?! 제발 철 좀 들어!","JPN":"他の戦隊があなたをみてどう思っているのか気にならないの？　お願いだから、もう少し大人になって！","ENG":"What would other Division members think of you? Grow up!","TWN":"其他戰隊的人看到會怎麼說你？！拜託成熟點吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아토믹 힐데에에에에!!","JPN":"アトミック・ヒルデエエエエェェ！！","ENG":"Atomic Hildeeeeeeeeeee!!","TWN":"希爾德原子子子子！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SKILL"},"R":null}},"sfx":"FX_COMBAT_ONLY_LEE_SUYEON_HYPER_ATTACK"},{"id":"L9_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"퍼니시먼트으으으으으!!!!","JPN":"パニッシュメントオオォォォォ！！！！","ENG":"Punishmeeeeeeeeent!","TWN":"懲戒戒戒戒！！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저, 정말 치열한 접전이었는데요……!","JPN":"ほ、本当に激しい接戦でしたね……！","ENG":"Th-that was a tight match!","TWN":"戰…戰況真是激烈……！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"네. 시간 초과로 무승부.","JPN":"はい、時間超過で引き分け。","ENG":"Yes. The match was tied due to a timeout.","TWN":"好的，時間到，平手。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"규정에 따라 두 팀 전부 탈락. 비치발리볼이라더니 해변을 발칵 뒤집어 놨네.","JPN":"規定によって両チームとも脱落。ビーチバレーボールをやれと言ったのに、こりゃあ戦争レベルだな。","ENG":"Both the teams are disqualified as per the rules. It was supposed to be a beach volleyball game, but they destroyed the whole beach.","TWN":"按照規則兩隊都淘汰，打個沙灘排球把整個海灘都掀了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"Huff, huff...","TWN":"呼呼……呼呼……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Ugh...","TWN":"呼呼……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"소, 손은 좀 괜찮나? 방금 배구공이 빛을 뿜던 것 같은데?","JPN":"て、手は大丈夫か？　今ボールが一瞬光を放ったような気がしたが。","ENG":"H-how’s your hand? I think I saw the volleyball shining with light.","TWN":"你…你的手還好嗎？我剛看到排球好像發光欸？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"네. 걱정해 주셔서 감사하지만, 이 정도는 소독제만 발라도 낫습니다.","JPN":"はい。心配していただくのはありがたいですが、これぐらいは消毒剤を塗るだけで治ります。","ENG":"Thank you for your concern, but a bandage will be enough.","TWN":"多謝老闆關心，一點皮肉傷，擦個藥膏就好。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"내 회심의 아토믹 힐데 퍼니시먼트를 받아내다니…….","JPN":"私の会心のアトミック・ヒルデ・パニッシュメントを受け止めるなんて……","ENG":"I didn’t expect you’d return my Atomic Hilde Punishment...","TWN":"竟然可以接住我的希爾德原子懲戒……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아줌마! 나랑 같이 가자! 아줌마라면 우리 전대에 합류할 자격이 있어!","JPN":"おばさん！　私と一緒に行こう！　おばさんなら、うちの戦隊に合流する資格があるわ！","ENG":"Hey, old lady! Come with me! You deserve to be in my Division!","TWN":"大嬸！跟我走！你有資格加入我們戰隊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"썩 사라져요. 그쪽과는 단 1초도 같은 공기를 마시고 싶지 않습니다.","JPN":"さっさと消えなさい。そっちとはたった1秒も同じ空間で同じ空気を吸いたくありません。","ENG":"Go away. I can’t stand you, not for a single second.","TWN":"快滾吧！我連1秒鐘都不想再和你呼吸相同的空氣。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"응? 사라지다니? 어디로 말이야?","JPN":"うん？　消える？　どこに？","ENG":"Huh? Go where?","TWN":"嗯？我要滾去哪裡？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"으응……? 어째 몸이 반짝반짝 흩어지고 있지 않냥?","JPN":"ううん？　なんか身体がキラキラと光って散ってないかにゃん？","ENG":"Nya? You are dissipating into shiny particles.","TWN":"嗯……？不覺得身體好像散開了?"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"진짜다?! 어떻게 된 거야, 이거?!","JPN":"ホントだ！　どうなってるの、これ？","ENG":"You’re right! What’s going on?!","TWN":"真的欸？！怎麼會這樣？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"너무 놀라지 말게. 본래 자네가 있어야 하는 곳으로 돌아갈 뿐이야.","JPN":"あまり驚かないでくれ。本来君が居るべき場所へ戻るだけだ。","ENG":"Don’t be so surprised. You’re going back to where you come from.","TWN":"不要嚇到，你們只是回到原本屬於你們的地方而已。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아하. 그럼 스승님이 있는 곳이겠네.","JPN":"そうなんだ。ってことは師匠のところなんだね。","ENG":"Oh, then I’m going back to where the Master is.","TWN":"哦～那應該是師父在地方吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"헤헷. 그래도 뭔가 아쉽네. 모처럼 걱정없이 전력으로 싸울 만한 사람을 만났는데.","JPN":"ヘヘッ。なんか寂しくなるな。せっかく余計なことを心配せず全力で戦える人に出会えたのに。","ENG":"It’s a shame though. This is the first time I fought someone without holding back.","TWN":"嘿嘿～不過還真有點可惜，好不容易才遇到一個可以奮力一搏的對手。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"가기 전에 한 가지, 기억해 두면 좋겠군요.","JPN":"戻る前に一つ、覚えておいてほしいことがあります。","ENG":"Before you go, remember this one thing.","TWN":"在你離開前，請記住一件事。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어? 뭔데?","JPN":"ん？　なに？","ENG":"What is it?","TWN":"什麼？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"남들이 물러나라고 할 때는 얌전히 물러나세요.","JPN":"後ろに下がれと言われた時は、大人しく下がってください。","ENG":"When others tell you to stay back, please listen.","TWN":"人家叫你退的時候就要退。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그렇게 주위를 살필 줄 모르고 혼자만 설치다가는 언젠가 큰코 다칠 날이 올 겁니다.","JPN":"今みたいに調子に乗って一人で出しゃばると、いつか痛い目にあう日が来ます。","ENG":"If you keep on running wild on your own, eventually you will be sorry.","TWN":"要懂得察言觀色，不要我行我素，否則總有一天會吃大虧的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아하. 아줌마, 멀대랑 비슷한 과구나?","JPN":"へえ。おばさん、ヒョロガリと同じ部類の人なんだね。","ENG":"Oh, you’re kinda like the Beanstalk, aren’t you?","TWN":"哈，大嬸你跟傻大個一樣是囉嗦系的嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마. 스승님이랑 내가 함께 있으면 우린 천하무적이거든!","JPN":"心配しないで。師匠と私が一緒にいれば、私たちは天下無敵なんだから！","ENG":"Don’t worry about it. As long as I’m with the Master, I’m invincible!","TWN":"放心吧！只要和師父一起，我們就是天下無敵！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"우리가 앞장서지 않으면 누가 침식체랑 싸우려고 하겠어?","JPN":"あと私たちが先頭に立たないと、誰も侵食体と戦おうとしないと思うよ？","ENG":"Who will fight C.O.s if we don’t fight them?","TWN":"我們不帶頭的話，誰敢對抗侵蝕體？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……그래요. 그렇겠죠. 괜한 잔소리였습니다.","JPN":"……はい、そうですね。余計なことを言いました。","ENG":"... Yes. You’re right. I stepped out of line.","TWN":"……沒錯，你說的對，當我沒說過吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"하지만 걱정해 준 건 잊지 않을게.","JPN":"でも心配してくれたのは忘れないわ。","ENG":"But I do appreciate your concern.","TWN":"不過還是謝謝你的提醒。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"처치 곤란한 침식체가 나타나면 언제든 이 이수연 님을 찾으라고!","JPN":"倒すのが難しい侵食体が現れたら、いつでもこのカナミ・キズナを呼んでね！","ENG":"If you encounter C.O.s you can’t handle, call me anytime!","TWN":"不好對付的侵蝕體出現時，隨時找我李秀妍！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"……이제는 정말 돌아간 모양이군.","JPN":"……今回は本当に帰ったようだな。","ENG":"... It looks like she’s really gone this time.","TWN":"……這次是真的回去了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"괜찮겠나, 자네? 하고 싶었던 얘기는 더 많았을 텐데?","JPN":"それだけでいいのか？　言いたかったことは、他にも多かったと思うが。","ENG":"Are you alright? You must’ve had much more to say.","TWN":"沒關係嗎？你應該還有很多話想說吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아뇨. 말한다고 들을 리가 없다는 건 제가 더 잘 아니까요.","JPN":"ええ。話したって素直に従う性格ではないことくらい、私自身がよく知っています。","ENG":"It’s okay. She wouldn’t have listened to me.","TWN":"不了，就算我說了她也不會聽，這一點我很清楚。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"하지만……. 그래요. 저렇게나 골치 아픈 녀석이었군요.","JPN":"でも……そうですね。あんなにやんちゃで困る子だったんですね。","ENG":"But... yes. I now understand that I was very troublesome.","TWN":"只是……是啊，她就是那麼令人頭疼的傢伙。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 사장이랑 같이 있었나.","JPN":"なんだ、社長と一緒にいたのか。","ENG":"You are here, with the Boss.","TWN":"搞什麼？原來你和老闆在一起？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"스승님? 여긴 무슨 일이시죠?","JPN":"師匠？　こんなところまでどうしましたか？","ENG":"Master? What brought you here?","TWN":"師父？你怎麼會來這裡？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"관리부장이 전해 달라고 부탁하더군. 함선 안에서 주인 모를 맥주가 있었다면서 말이다.","JPN":"管理部長から渡してほしいと頼まれたんだ。艦船の中に持ち主不明のビールがあったそうだ。","ENG":"The Manager told me that she found some beer cans that don’t seem to belong to anyone.","TWN":"這是管理部長要我轉交給你的，說是在艦船裡找到的啤酒，不知道是誰的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼 난 이만 가도록 하지. 그걸로 목이라도 축여라.","JPN":"じゃあ、私は戻る。それで水分補給でもしろ。","ENG":"I’ll be going now. You can have the beer.","TWN":"那我先走了，你就用那個潤潤喉吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"쉬러 와서는 고생만 했던 모양이니.","JPN":"休みに来たのに苦労ばかりしたようだしな。","ENG":"It looks like you’ve had a hard time during your vacation.","TWN":"看你好像很累的樣子。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"스승님.","JPN":"師匠。","ENG":"Master.","TWN":"師父。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"음? 따로 할 말이 있나?","JPN":"うん？　何か言いたいことでも？","ENG":"Hmm? Is there something else you want to say?","TWN":"幹嘛？你有話要跟我說嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"어차피 할일도 없으실 텐데, 고생한 저를 위해 잠시 말동무라도 해 주시죠.","JPN":"どうせやることもないでしょうから、苦労した私のためにしばらく話し相手にでもなってください。","ENG":"I know you have nothing else to do. Why don’t you stay here with me?","TWN":"反正師父應該也沒甚麼事，不如就看在我很累的份上，陪我聊聊天吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님은 찾는 분이 많으셔서 말입니다. 오래 붙잡아 둘 수가 없군요.","JPN":"社長をお探しの方が多いですからね。長く捕まえておくことができません。","ENG":"Everyone is looking for the Boss. I can’t hold him down here any longer.","TWN":"老闆是大忙人，一堆人要找他，沒辦法停留太久。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래? 그런 것치고는 둘이 잘만 어울리던 것…….","JPN":"そうか？　その割には二人で仲良くいろんなことを……","ENG":"Really? I thought you two were having a good time...","TWN":"是喔？要聊天的話，老闆滿適合的……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……뭐야, 벌써 사라졌나?","JPN":"……なんだ、もう消えたのか？","ENG":"... Oh, he’s gone already.","TWN":"……也消失得太快了吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 푸념 들어 주는 것 정도라면 괜찮겠지.","JPN":"まあ、愚痴を聞くぐらいなら。","ENG":"Okay then, let me hear your complaint.","TWN":"好吧，如果只是聽你抱怨，那還可以接受啦。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"너무 싫은 티 내지는 마시죠. 휴일 수당은 넉넉히 챙겨 드릴 테니까요.","JPN":"そんなに嫌な顔はしないでください。休日手当は十分用意していますから。","ENG":"Don’t be so resentful. You will be paid extra for this.","TWN":"想要多一點假日津貼的話，請注意一下表情管理。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};